import{_ as r,o as a,c as e,a2 as o}from"./chunks/framework.KT0ECV7t.js";const g=JSON.parse('{"title":"MCP 学习笔记","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"learn/summary-mcp.md","filePath":"learn/summary-mcp.md","lastUpdated":null}'),n={name:"learn/summary-mcp.md"};function l(i,t,d,s,p,c){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="mcp-学习笔记" tabindex="-1">MCP 学习笔记 <a class="header-anchor" href="#mcp-学习笔记" aria-label="Permalink to &quot;MCP 学习笔记&quot;">​</a></h1><p>持续更新中。记录 MCP 协议的要点、最佳实践和常见问题。</p><h2 id="核心概念速查" tabindex="-1">核心概念速查 <a class="header-anchor" href="#核心概念速查" aria-label="Permalink to &quot;核心概念速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>一句话</th></tr></thead><tbody><tr><td>MCP Server</td><td>提供工具/资源的服务端程序</td></tr><tr><td>MCP Client</td><td>AI 侧消费者（LangChain Agent, Claude Desktop 等）</td></tr><tr><td>Transport</td><td>传输方式：stdio（本地）、HTTP（远程）</td></tr><tr><td>JSON-RPC</td><td>通信协议格式</td></tr><tr><td>FastMCP</td><td>Python 简化版 MCP Server 框架</td></tr><tr><td>langchain-mcp-adapters</td><td>LangChain 官方 MCP 桥接包</td></tr></tbody></table><h2 id="设计原则" tabindex="-1">设计原则 <a class="header-anchor" href="#设计原则" aria-label="Permalink to &quot;设计原则&quot;">​</a></h2><ul><li><strong>一个 Server 做一件事</strong> — 数学工具一个 Server，排版工具另一个</li><li><strong>Server 不依赖 AI</strong> — 可以在任何地方独立运行和测试</li><li><strong>函数签名就是文档</strong> — 清晰的参数名 + 类型标注 + docstring</li><li><strong>返回字符串</strong> — MCP 工具返回文本；结构化数据用 JSON 字符串</li><li><strong>错误用字符串返回</strong> — 不要抛异常，返回 &quot;Error: xxx&quot;</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q: MCP 和 OpenAI Function Calling 的区别？</strong></p><p>MCP 是协议标准，Function Calling 是 OpenAI 一家的实现。用 MCP 写的工具可以跨平台复用。</p><p><strong>Q: 什么时候用 stdio，什么时候用 HTTP？</strong></p><ul><li>stdio：本地开发、脚本、单用户场景</li><li>HTTP：部署到服务器、多用户访问、生产环境</li></ul><p><strong>Q: Go 能用 MCP 吗？</strong></p><p>可以。社区有 <code>mcp-go</code>，还有 <code>langchaingo-mcp-adapter</code>。你最强的 Go 可以直接用。</p><p><strong>Q: MCP Server 能调用 API 吗？</strong></p><p>能。MCP Server 就是普通程序，你可以在工具函数里发 HTTP 请求、查数据库、调其他 API。</p><h2 id="关键链接" tabindex="-1">关键链接 <a class="header-anchor" href="#关键链接" aria-label="Permalink to &quot;关键链接&quot;">​</a></h2><ul><li><a href="https://modelcontextprotocol.io/specification/2025-11-25" target="_blank" rel="noreferrer">MCP 规范</a></li><li><a href="https://modelcontextprotocol.info/zh-cn/specification/" target="_blank" rel="noreferrer">MCP 规范（中文）</a></li><li><a href="https://pypi.org/project/langchain-mcp-adapters/" target="_blank" rel="noreferrer">langchain-mcp-adapters</a></li></ul>',17)])])}const P=r(n,[["render",l]]);export{g as __pageData,P as default};
